        .AXI_DATA_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .APB_ADDR_WIDTH(32),
        .APB_DATA_WIDTH(32)
    ) u_apb_shim_stream_apb (
        .aclk(aclk),
        .aresetn(aresetn),
